<?php
namespace App\Services\Billing;use App\Models\{Invoice,Payment,Subscription};use App\Notifications\{InvoiceGeneratedNotification,PaymentReceivedNotification};use App\Services\Audit\AuditLogService;use Illuminate\Support\Facades\DB;
class BillingService{public function __construct(private AuditLogService $audit){}public function createInvoiceForSubscription(Subscription $s):Invoice{return DB::transaction(function()use($s){$plan=$s->plan;$price=$s->billing_cycle==='yearly'?($plan?->yearly_price??$plan?->monthly_price*12):($plan?->monthly_price??0);$invoice=Invoice::create(['workspace_id'=>$s->workspace_id,'subscription_id'=>$s->id,'invoice_number'=>$this->generateInvoiceNumber(),'status'=>'issued','currency'=>$plan?->currency??$s->workspace?->currency??'USD','issue_date'=>today(),'due_date'=>today()->addDays(config('billing.invoice_due_days',15))]);$invoice->items()->create(['workspace_id'=>$s->workspace_id,'description'=>($plan?->name??'Subscription').' plan','quantity'=>1,'unit_price'=>$price,'total'=>$price]);$this->calculateInvoiceTotals($invoice);$this->audit->log('invoice_generated',$invoice,[],['total'=>$invoice->total],$s->workspace_id);$s->workspace?->owner?->notify(new InvoiceGeneratedNotification($invoice));return $invoice;});}public function markInvoicePaid(Invoice $i,Payment $p):void{DB::transaction(function()use($i,$p){$paid=$i->payments()->where('status','successful')->sum('amount')+$p->amount;$i->update(['amount_paid'=>$paid,'amount_due'=>max(0,$i->total-$paid),'status'=>$paid>=$i->total?'paid':$i->status,'paid_at'=>$paid>=$i->total?now():$i->paid_at]);if($i->status==='paid'&&$i->subscription)$i->subscription->update(['status'=>'active']);$this->audit->log('invoice_marked_paid',$i,[],['payment_id'=>$p->id],$i->workspace_id);$i->workspace?->owner?->notify(new PaymentReceivedNotification($p));});}public function calculateInvoiceTotals(Invoice $i):void{$subtotal=$i->items()->sum('total');$total=max(0,$subtotal-$i->discount_total+$i->tax_total);$i->update(['subtotal'=>$subtotal,'total'=>$total,'amount_due'=>max(0,$total-$i->amount_paid)]);}public function generateInvoiceNumber():string{return 'INV-'.now()->format('Ymd').'-'.strtoupper(str()->random(8));}public function generatePaymentNumber():string{return 'PAY-'.now()->format('Ymd').'-'.strtoupper(str()->random(8));}}
